  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ================= Enums =================\n\nenum Role {\n  ADMIN\n  GERENTE\n  OPERADOR\n}\n\nenum StatusViagem {\n  PROGRAMADA\n  EM_ANDAMENTO\n  FINALIZADA\n  CANCELADA\n}\n\nenum TipoAtraso {\n  SAIDA_BASE\n  TEMPO_PARADA_EXCEDIDO\n  DESLOCAMENTO_ROTA\n}\n\n// ================= Cadastros Básicos =================\n\nmodel Base {\n  id     String @id @default(cuid())\n  nome   String @unique // <--- ADICIONE O @unique AQUI\n  cidade String\n\n  // Novos campos para Geocerca\n  latitude   Float?\n  longitude  Float?\n  raioMetros Int    @default(500)\n\n  // Relações\n  usuarios       User[]\n  viagensOrigem  Viagem[]              @relation(\"BaseOrigem\")\n  viagensDestino Viagem[]              @relation(\"BaseDestino\")\n  justificativas JustificativaAtraso[]\n  paradasPadrao  ParadaPadrao[]\n  paradasViagem  ParadaViagem[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel User {\n  id            String    @id @default(cuid())\n  name          String? // Mudamos de 'nome' para 'name'\n  email         String    @unique\n  emailVerified DateTime? // Coluna exigida pelo NextAuth\n  image         String? // Coluna exigida pelo NextAuth\n  senhaHash     String\n  role          Role      @default(OPERADOR)\n\n  // Relacionamento opcional: Admin pode não ter base, mas Gerente/Operador sim\n  baseId String?\n  base   Base?   @relation(fields: [baseId], references: [id])\n\n  justificativas JustificativaAtraso[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Veiculo {\n  id        String  @id // ID que vem da Sascar (ex: 2225152)\n  placa     String  @unique\n  descricao String?\n\n  viagens     Viagem[]\n  telemetrias Telemetria[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ================= Operação e Viagens =================\n\nmodel Viagem {\n  id            String @id // ID/Nº da Viagem vindo do relatório manual (ex: 37627407)\n  motorista     String\n  rotaDescricao String // Ex: CURITIBA-PR X ITAJAI-SC\n\n  veiculoId String\n  veiculo   Veiculo @relation(fields: [veiculoId], references: [id])\n\n  baseOrigemId String\n  baseOrigem   Base   @relation(\"BaseOrigem\", fields: [baseOrigemId], references: [id])\n\n  baseDestinoId String\n  baseDestino   Base   @relation(\"BaseDestino\", fields: [baseDestinoId], references: [id])\n\n  status StatusViagem @default(PROGRAMADA)\n\n  // Datas Planejadas (Vindas do relatório manual)\n  prevInicioReal DateTime\n  prevFimReal    DateTime\n\n  // Datas Reais (Preenchidas dinamicamente pela telemetria/sistema)\n  dataInicioEfetivo DateTime?\n  dataFimEfetivo    DateTime?\n\n  rotaPadraoId  String?\n  rotaPadrao    RotaPadrao?    @relation(fields: [rotaPadraoId], references: [id])\n  paradasViagem ParadaViagem[]\n\n  // >>> REGRA DE NEGÓCIO: Compensação de Horário <<<\n  // Se chegou atrasado na base de transbordo, este campo é atualizado com o novo horário limite de saída\n  novaPrevisaoSaida DateTime?\n\n  justificativas JustificativaAtraso[]\n  telemetrias    Telemetria[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel JustificativaAtraso {\n  id       String @id @default(cuid())\n  viagemId String\n  viagem   Viagem @relation(fields: [viagemId], references: [id])\n\n  tipoAtraso TipoAtraso\n  motivo     String     @db.Text\n\n  usuarioId String\n  usuario   User   @relation(fields: [usuarioId], references: [id])\n\n  // Se o atraso for de saída ou de parada, vincula a qual base ocorreu\n  baseId String?\n  base   Base?   @relation(fields: [baseId], references: [id])\n\n  tempoAtrasoMinutos Int // Quantos minutos de atraso foram justificados\n\n  createdAt DateTime @default(now())\n}\n\n// ================= Integração em Tempo Real =================\n\nmodel Telemetria {\n  id        String  @id @default(cuid())\n  veiculoId String\n  veiculo   Veiculo @relation(fields: [veiculoId], references: [id])\n\n  viagemId String? // Pode ser nulo se o veículo estiver rodando sem viagem alocada\n  viagem   Viagem? @relation(fields: [viagemId], references: [id])\n\n  latitude   Float\n  longitude  Float\n  ignicao    Boolean\n  velocidade Int?\n\n  // Horários\n  dataHoraUtc   DateTime // Dado bruto da API\n  dataHoraLocal DateTime // Já ajustado para GMT-3 na inserção\n\n  createdAt DateTime @default(now())\n\n  @@index([veiculoId, dataHoraLocal(sort: Desc)]) // Índice crucial para buscar a última posição rápido\n  @@index([viagemId])\n}\n\n// ================= MATRIZ DE ROTAS =================\n\nmodel RotaPadrao {\n  id      String         @id @default(cuid())\n  nome    String         @unique // Ex: APUCARANA X MARINGÁ X CASCAVEL X TOLEDO\n  paradas ParadaPadrao[]\n  viagens Viagem[]\n}\n\nmodel ParadaPadrao {\n  id     String     @id @default(cuid())\n  rotaId String\n  rota   RotaPadrao @relation(fields: [rotaId], references: [id], onDelete: Cascade)\n\n  baseId String\n  base   Base   @relation(fields: [baseId], references: [id])\n\n  ordem Int // 0 = Origem, 1 = Primeira Parada, etc.\n\n  // Guardamos como texto \"HH:MM:SS\" (ex: \"22:00:00\") para facilitar a clonagem\n  prevChegada String?\n  prevSaida   String?\n}\n\n// ================= HISTÓRICO DA VIAGEM REAL =================\n\nmodel ParadaViagem {\n  id       String @id @default(cuid())\n  viagemId String\n  viagem   Viagem @relation(fields: [viagemId], references: [id], onDelete: Cascade)\n\n  baseId String\n  base   Base   @relation(fields: [baseId], references: [id])\n\n  ordem Int\n\n  // Datas absolutas calculadas para o dia específico da viagem\n  prevChegada DateTime?\n  prevSaida   DateTime?\n\n  // Preenchido dinamicamente pela telemetria\n  dataChegadaEfetiva DateTime?\n  dataSaidaEfetiva   DateTime?\n}\n",
